const body = $json.body || $json;
const callId = 'sim-' + Date.now() + '-' + Math.floor(Math.random()*1000);
const metadata = body.assistant?.metadata || body.metadata || {};
const overrides = body.assistantOverrides?.variableValues || body.variableValues || {};

// Leer variables
const agenteTipo = overrides.agente_tipo || metadata.agente_tipo || "COBROS";
const monto = Number(overrides.valor || overrides.monto || 0);
const fechaVencimiento = overrides.fecha_maxima || overrides.fecha_vencimiento || new Date().toISOString().split('T')[0];
const numeroTelefono = body.customer?.number || "+593999999999";

const rand = Math.random();
let connected = false;
let endedReason = '';
let escenario = 0; // 1: No conecta, 2: Tercero, 3: Titular No Acepta, 4: Titular Acepta

if (rand < 0.25) {
    escenario = 1;
} else if (rand < 0.40) {
    escenario = 2;
} else if (rand < 0.70) {
    escenario = 3;
} else {
    escenario = 4;
}

let structuredData = {
    canal: "Llamada Simulada",
    sentimiento: "neutral"
};

let duracionLlamada = 0;

if (escenario === 1) {
    // No conecto
    connected = false;
    const randFail = Math.random();
    if (randFail < 0.5) { endedReason = 'customer-busy'; structuredData.codigo_respuesta = 'OCU08'; }
    else if (randFail < 0.8) { endedReason = 'no-answer'; structuredData.codigo_respuesta = 'NOCON05'; }
    else { endedReason = 'voicemail'; structuredData.codigo_respuesta = 'CONTESAUT'; }

    structuredData.Nomenclatura = "NO CONTACTO NO JUSTIFICADO";
    structuredData.contactoalo = "No";
    structuredData.es_familiar = "No";
    structuredData.aceptacion = "No";
    structuredData.Resumen_Llamada = "Llamada no fue contestada.";
    duracionLlamada = 5 + Math.floor(Math.random() * 10);

} else if (escenario === 2) {
    // Tercero
    connected = true;
    endedReason = 'customer-ended-call';
    structuredData.Nomenclatura = "CONTACTO FALLIDO JUSTIFICADO";
    structuredData.codigo_respuesta = "MSJTERCEROS";
    structuredData.contactoalo = "Si";
    structuredData.es_familiar = Math.random() < 0.5 ? "Si" : "No";
    structuredData.aceptacion = "No";
    structuredData.Resumen_Llamada = "Contesto un tercero, se dejo mensaje.";
    duracionLlamada = 20 + Math.floor(Math.random() * 30);

} else if (escenario === 3) {
    // Titular No Acepta
    connected = true;
    endedReason = 'customer-ended-call';
    structuredData.Nomenclatura = "NO ACEPTACION";
    const motivos = ['NOTIETRA', 'SINJUS', 'PROBLSALUD', 'DEUOTRPER'];
    structuredData.codigo_respuesta = motivos[Math.floor(Math.random() * motivos.length)];
    structuredData.contactoalo = "Si";
    structuredData.es_familiar = "No";
    structuredData.aceptacion = "No";
    structuredData.Resumen_Llamada = "Titular contesta pero no acepta el pago por motivo: " + structuredData.codigo_respuesta;
    structuredData.sentimiento = "negativo";
    duracionLlamada = 40 + Math.floor(Math.random() * 60);

} else if (escenario === 4) {
    // Titular Acepta (Promesa de Pago)
    connected = true;
    endedReason = 'customer-ended-call';
    structuredData.Nomenclatura = "PENDIENTE DE ACEPTACION";
    structuredData.codigo_respuesta = "COMPAGO";
    structuredData.contactoalo = "Si";
    structuredData.es_familiar = "No";
    structuredData.aceptacion = "Si";
    structuredData.Resumen_Llamada = "Titular acepta compromiso de pago.";
    structuredData.sentimiento = "positivo";

    // Calcular monto y fecha segun politicas
    if (agenteTipo === "PREVENTIVA") {
        structuredData.monto_promesa = monto.toFixed(2);
        structuredData.fecha_promesa = fechaVencimiento;
    } else {
        // COBROS: 30% a 100% del monto
        const porcentaje = 0.30 + (Math.random() * 0.70);
        structuredData.monto_promesa = (monto * porcentaje).toFixed(2);

        // Fecha promesa: hoy a 48 horas (0 a 2 dias)
        const dias = Math.floor(Math.random() * 3);
        const fp = new Date();
        fp.setDate(fp.getDate() + dias);
        structuredData.fecha_promesa = fp.toISOString().split('T')[0];
    }
    duracionLlamada = 60 + Math.floor(Math.random() * 60);
}

const startTimeMs = Date.now() - (duracionLlamada * 1000);
const startTime = new Date(startTimeMs).toISOString();
const endTime = new Date().toISOString();

const payload = {
    message: {
        type: "end-of-call-report",
        call: {
            id: callId,
            customer: { number: numeroTelefono },
            startedAt: startTime,
            endedAt: endTime,
        },
        endedReason: endedReason,
        transcript: connected ? '[Simulacion] Llamada escenario ' + escenario + '.' : "",
        analysis: {
            structuredData: structuredData
        },
        metadata: metadata
    }
};

return { json: payload };
